const ALCConfigEntry* alcLookupPinConfig(UInt32 codecId, UInt32 layoutId)
{
    int lo = 0, hi = ALC_CONFIG_ENTRIES_COUNT - 1;
    while (lo <= hi) {
        int mid = (lo + hi) / 2;
        const ALCConfigEntry *e = &gALCConfigEntries[mid];
        if (e->codecId < codecId) {
            lo = mid + 1;
        } else if (e->codecId > codecId) {
            hi = mid - 1;
        } else if (e->layoutId < layoutId) {
            lo = mid + 1;
        } else if (e->layoutId > layoutId) {
            hi = mid - 1;
        } else {
            return e;
        }
    }
    return 0;
}
